   481→    const [found, final] = intervals
   482→      .sort((a, b) => a.s - b.s)
   483→      .reduce(
   484→        ([sofar, current], item) => {
   485→          if (!current) {
   486→            return [sofar, item];
   487→          } else if (current.overlaps(item) || current.abutsStart(item)) {
   488→            return [sofar, current.union(item)];
