   496→      found.push(final);
   497→    }
   498→    return found;
   499→  }
   500→
   501→  /**
   502→   * Return an array of Intervals representing the spans of time that only appear in one of the specified Intervals.
   503→   * @param {Array} intervals
   504→   * @return {Array}
   505→   */
