   533→
   534→  /**
   535→   * Return an Interval representing the span of time in this Interval that doesn't overlap with any of the specified Intervals.
   536→   * @param {...Interval} intervals
   537→   * @return {Array}
   538→   */
   539→  difference(...intervals) {
   540→    return Interval.xor([this].concat(intervals))
   541→      .map((i) => this.intersection(i))
   542→      .filter((i) => i && !i.isEmpty());
   543→  }
   544→
   545→  /**
   546→   * Returns a string representation of this Interval appropriate for debugging.
   547→   * @return {string}
   548→   */
   549→  toString() {
   550→    if (!this.isValid) return INVALID;
   551→    return `[${this.s.toISO()} – ${this.e.toISO()})`;
   552→  }
   553→
   554→  /**
   555→   * Returns a string representation of this Interval appropriate for the REPL.
   556→   * @return {string}
