const { Interval, DateTime } = require('./src/luxon.js');

console.log('Testing Interval.fromISO bug');

// Test case from bug description
const interval = Interval.fromISO("1988-04-15T09/15");
console.log('Result:');
console.log('Interval.fromISO("1988-04-15T09/15").toString():');
console.log(interval.toString());

console.log('\nExpected behavior:');
console.log('Interval.fromISO("1988-04-15T09/15").toString():');
console.log('[1988-04-15T09:00:00.000+01:00 – 1988-04-15T15:00:00.000+01:00)');

console.log('\nDebug info:');
if (interval.isValid) {
    console.log('Start:', interval.start.toISO());
    console.log('End:', interval.end.toISO());
    console.log('Start object:', interval.start.toObject());
    console.log('End object:', interval.end.toObject());
} else {
    console.log('Interval is invalid:', interval.invalidReason);
}

