// Simple test to reproduce the bug using Jest
const { Interval } = require('./build/node/luxon.js');

describe('ISO 8601 Interval parsing bug', () => {
    test('should parse start/end notation correctly', () => {
        // Test case from bug description
        const interval = Interval.fromISO("1988-04-15T09/15");

        expect(interval.isValid).toBe(true);

        const start = interval.start;
        const end = interval.end;

        // According to ISO 8601, missing elements in end should be same as start
        expect(start.year).toBe(1988);
        expect(start.month).toBe(4);
        expect(start.day).toBe(15);
        expect(start.hour).toBe(9);

        // End should have same date as start, only different hour
        expect(end.year).toBe(1988);
        expect(end.month).toBe(4);
        expect(end.day).toBe(15);
        expect(end.hour).toBe(15);

        console.log('Actual result:', interval.toString());
        console.log('Start:', start.toISO());
        console.log('End:', end.toISO());
    });
});

